import torch
import torch.nn as nn
from torch.utils.data import Dataset
import numpy as np

class CIFAR100LT(Dataset):
    def __init__(self, filepath, transform=None):
        data = torch.load(filepath, map_location='cpu')
        self.images = data['images']
        self.labels = data['labels']
        self.transform = transform

    def __len__(self):
        return len(self.labels)

    def __getitem__(self, idx):
        img = self.images[idx]
        label = self.labels[idx]
        if self.transform:
            img = self.transform(img)
        return img, label

def compute_balanced_accuracy(predictions, labels, num_classes):
    acc_per_class = []
    for c in range(num_classes):
        idx = labels == c
        if idx.sum() > 0:
            acc_per_class.append((predictions[idx] == c).float().mean().item())
        else:
            acc_per_class.append(torch.nan)
    valid_accs = [acc for acc in acc_per_class if not torch.isnan(torch.tensor(acc))]
    return sum(valid_accs) / len(valid_accs) if valid_accs else 0.0

def compute_effective_weights(class_counts, num_classes, beta=0.9999):
    """Class-balanced re-weighting (Cui et al. 2019).
    Returns per-class weights proportional to (1-beta)/(1-beta^{n_c})"""
    weights = []
    for c in range(num_classes):
        n = class_counts.get(c, 0)
        if n == 0:
            weights.append(0.0)
        else:
            eff_num = 1.0 - beta ** n
            weight = (1.0 - beta) / max(eff_num, 1e-6)
            weights.append(weight)
    return weights

class FocalLoss(nn.Module):
    """Focal loss with class weights."""
    def __init__(self, class_weights=None, gamma=2.0, reduction='mean'):
        super().__init__()
        self.class_weights = class_weights
        self.gamma = gamma
        self.reduction = reduction

    def forward(self, logits, targets):
        ce_loss = torch.nn.functional.cross_entropy(logits, targets, weight=self.class_weights, reduction='none')
        pt = torch.exp(-ce_loss)
        focal_loss = ((1 - pt) ** self.gamma * ce_loss)
        if self.reduction == 'mean':
            return focal_loss.mean()
        elif self.reduction == 'sum':
            return focal_loss.sum()
        else:
            return focal_loss

def mixup_data(x, y, alpha=0.5):
    """Returns mixed inputs, pairs of targets, and lambda"""
    if alpha > 0:
        lam = np.random.beta(alpha, alpha)
    else:
        lam = 1
    batch_size = x.size()[0]
    index = torch.randperm(batch_size, device=x.device)
    mixed_x = lam * x + (1 - lam) * x[index, :]
    y_a, y_b = y, y[index]
    return mixed_x, y_a, y_b, lam
